{
  "steps": [
    {
      "text": "Clear a large table, remove plastic bags, and place a Phillips screwdriver nearby. You should have the case, motherboard, CPU, cooler, RAM, storage, GPU, PSU, and cables within reach.",
      "title": "Prepare Your Workspace"
    },
    {
      "text": "Touch the metal case frame before handling parts. If you have an anti-static wrist strap, clip it to the case. This helps protect components from static discharge.",
      "title": "Ground Yourself"
    },
    {
      "text": "Remove both side panels from the case. Set the screws in a small cup so they do not roll away. You should see the empty motherboard tray inside.",
      "title": "Open the Case"
    },
    {
      "text": "Place the motherboard on top of its cardboard box with the CPU socket facing up. The board should sit flat and stable while you install parts.",
      "title": "Set Down the Motherboard"
    },
    {
      "text": "Lift the CPU socket retention arm. On Intel boards, lift the metal cover too. The socket should be open without touching the tiny pins or contacts.",
      "title": "Open the CPU Socket"
    },
    {
      "text": "Hold the CPU by its edges and line up the small triangle on the CPU with the triangle on the socket. It should sit flat without pressure.",
      "title": "Align the CPU"
    },
    {
      "text": "Lower the CPU straight into the socket. Do not slide it. If it is aligned correctly, it will drop into place and sit level.",
      "title": "Seat the CPU"
    },
    {
      "text": "Lower the socket cover and press the retention arm back under its hook. Some Intel plastic covers pop off; keep it in the motherboard box.",
      "title": "Lock the CPU"
    },
    {
      "text": "Place a pea-sized dot of thermal paste in the center of the CPU heat spreader. You should see one small dot, not a spread-out layer.",
      "title": "Apply Thermal Paste"
    },
    {
      "text": "Set the CPU cooler onto the CPU and line up its screws or brackets with the motherboard mounts. The cooler should sit squarely over the CPU.",
      "title": "Position the Cooler"
    },
    {
      "text": "Tighten the cooler screws in a cross pattern, a few turns at a time. Stop when the cooler is firmly seated and does not wiggle.",
      "title": "Secure the Cooler"
    },
    {
      "text": "Plug the cooler fan cable into the motherboard header labeled `CPU_FAN`. The connector only fits one way, and the cable should click or sit firmly.",
      "title": "Connect the CPU Fan"
    },
    {
      "text": "Open the clips on the recommended RAM slots, usually `A2` and `B2`. Check your motherboard manual if the labels are unclear.",
      "title": "Open the RAM Slots"
    },
    {
      "text": "Line up the notch on the RAM stick with the slot and press straight down until the clips snap closed. The stick should be level and locked in.",
      "title": "Install the RAM"
    },
    {
      "text": "Unscrew the M.2 cover or standoff screw on the motherboard. You should see the M.2 slot ready for the storage drive.",
      "title": "Open the M.2 Slot"
    },
    {
      "text": "Slide the M.2 drive into the slot at a slight angle until it is fully seated. The gold contacts should mostly disappear inside the connector.",
      "title": "Insert the M.2 Drive"
    },
    {
      "text": "Press the M.2 drive down and fasten it with the screw or latch. The drive should lie flat and not spring upward.",
      "title": "Secure the M.2 Drive"
    },
    {
      "text": "Check the case motherboard tray for standoffs that match your motherboard size. Add or move standoffs so each screw hole has support underneath.",
      "title": "Check the Standoffs"
    },
    {
      "text": "Snap the separate I/O shield into the rear case opening if your board has one. Press all four corners until it clicks flush with the case.",
      "title": "Install the I/O Shield"
    },
    {
      "text": "Lower the motherboard into the case, aligning rear ports with the I/O shield and screw holes with standoffs. The board should rest flat.",
      "title": "Place the Motherboard"
    },
    {
      "text": "Fasten the motherboard screws into the standoffs. Tighten until snug, not overly tight. The board should no longer shift when touched.",
      "title": "Secure the Motherboard"
    },
    {
      "text": "Slide the power supply into its case bay with its fan facing a vent. The screw holes should line up at the back of the case.",
      "title": "Insert the Power Supply"
    },
    {
      "text": "Fasten the power supply with the four rear screws. It should sit firmly in the bay without moving.",
      "title": "Secure the Power Supply"
    },
    {
      "text": "Plug the large `24-pin ATX` cable into the motherboard power socket. Press until the latch clicks over the tab.",
      "title": "Connect Motherboard Power"
    },
    {
      "text": "Plug the `8-pin CPU` or `4+4 CPU` cable into the socket near the top of the motherboard. It should click firmly into place.",
      "title": "Connect CPU Power"
    },
    {
      "text": "Press the case power switch connector onto the motherboard pins labeled `PWR_SW`. If you do not see the label, use the motherboard manual diagram.",
      "title": "Connect the Power Button"
    },
    {
      "text": "Plug each case fan into a motherboard header labeled `SYS_FAN` or `CHA_FAN`. The fan connector should sit firmly on the pins.",
      "title": "Connect the Case Fans"
    },
    {
      "text": "Remove the rear expansion slot covers aligned with the top PCIe x16 slot. Keep the screws; you will use them to secure the GPU.",
      "title": "Remove GPU Slot Covers"
    },
    {
      "text": "Press the latch at the end of the top PCIe x16 slot down or outward. The slot should be open and ready for the graphics card.",
      "title": "Open the PCIe Slot"
    },
    {
      "text": "Line up the GPU with the top PCIe x16 slot and rear case opening, then press straight down until the latch clicks closed.",
      "title": "Install the GPU"
    },
    {
      "text": "Fasten the GPU bracket to the case using the slot cover screws. The card should sit level and not sag heavily at the rear bracket.",
      "title": "Secure the GPU"
    },
    {
      "text": "Plug the required `PCIe` power cable into the GPU. Use `6+2` connectors as needed, and confirm each latch clicks into place.",
      "title": "Connect GPU Power"
    },
    {
      "text": "Mount any 2.5-inch or 3.5-inch SATA drive in a drive tray or bracket. It should be screwed in or latched so it cannot slide.",
      "title": "Install SATA Storage"
    },
    {
      "text": "Plug a SATA data cable from the drive to a motherboard SATA port. The L-shaped connector fits one way and should feel secure.",
      "title": "Connect SATA Data"
    },
    {
      "text": "Plug a SATA power connector from the power supply into the drive. The wider L-shaped connector should slide in without force.",
      "title": "Connect SATA Power"
    },
    {
      "text": "Bundle loose cables behind the motherboard tray with zip ties or Velcro straps. Keep cables clear of fans and the GPU fan blades.",
      "title": "Tidy the Cables"
    },
    {
      "text": "Plug the monitor cable into the GPU, not the motherboard video port. You should feel the HDMI or DisplayPort connector seat firmly.",
      "title": "Connect the Monitor"
    },
    {
      "text": "Plug the keyboard into a rear USB port. A wired keyboard is best for the first startup because it should work before drivers are installed.",
      "title": "Connect the Keyboard"
    },
    {
      "text": "Plug the power cord into the PSU and wall outlet, then flip the PSU switch to `I`. The system now has standby power.",
      "title": "Turn On PSU Power"
    },
    {
      "text": "Press the case power button once. Fans should spin, lights may turn on, and the monitor should show the motherboard logo or BIOS screen.",
      "title": "Start the PC"
    },
    {
      "text": "Look for the CPU, RAM amount, storage drive, and GPU on the BIOS screen. If they appear, the core assembly is successful.",
      "title": "Verify the Build"
    }
  ]
}
